237	/**
238	 * A very subtle brand watermark behind every page: the yin-yang mark bled off
239	 * the content area's bottom-right corner at low opacity. Decorative only
240	 * (`aria-hidden`, no pointer events). The mark is clipped by *this* layer
241	 * (`inset:0; overflow:hidden`), not by the Content itself — so real page
242	 * content can still overflow/scroll normally; only the watermark is clipped.
243	 */
244	function BrandWatermark() {
245	  return (
246	    <div
247	      aria-hidden
248	      style={{
249	        position: 'absolute',
250	        inset: 0,
251	        overflow: 'hidden',
252	        pointerEvents: 'none',
253	      }}
254	    >
255	      <div style={{ position: 'absolute', right: -70, bottom: -70, opacity: 0.05, lineHeight: 0 }}>
256	        <BrandMark size={460} />
257	      </div>
258	    </div>
259	  );
260	}
