12	/**
13	 * Assets list (`/assets`, ADR 0034 gap G-d phase 2, #760) — the read-only
14	 * browse/reason surface over data assets. Each row is an asset the caller can see
15	 * (derived from suite grants; the backend filters), with the health rolled up
16	 * across the composing suites the caller can view. Click-through to the detail.
17	 *
18	 * This is phase 2 — a sidebar nav addition, **not** the navigation inversion
19	 * (that is phase 4, deliberately last): suites stay the primary browse surface.
20	 */
21	export function Assets() {
22	  const navigate = useNavigate();
23	  const { state } = useAsyncData(listAssets);
24	
25	  return (
26	    <Page>
27	      <Typography.Title level={3} style={{ margin: 0 }}>
28	        Assets
29	      </Typography.Title>
30	      <Typography.Paragraph type="secondary" style={{ margin: 0 }}>
31	        The tables and files your suites monitor. Health is rolled up across every suite you can see
32	        that targets the asset.
33	      </Typography.Paragraph>
34	      <AsyncBody state={state} loadingText="Loading assets…" errorTitle="Failed to load assets">
35	        {(assets) => <AssetsTable assets={assets} onOpen={(id) => navigate(`/assets/${id}`)} />}
36	      </AsyncBody>
37	    </Page>
