1	import { api } from './client';
2	
3	/**
4	 * Assets API — the read-only browse/reason surface over `assets` (ADR 0034,
5	 * #760). Assets are what users reason about; suites remain how checks execute.
6	 *
7	 * **Authz is derived, never granted** (backend `asset_view_service`): an asset is
8	 * visible iff the caller can view ≥1 suite targeting it, the aggregation is
9	 * filtered to their grants, and an asset outside their grants 404s (no-leak). The
10	 * client never has to scope — it just renders what the API returns.
11	 */
12	
13	/** A suite's latest run outcome — mirrors the backend `RunOutcomeRead`. */
14	export interface RunOutcome {
15	  run_id: string | null;
16	  /** Execution lifecycle (queued|running|succeeded|failed|cancelled), or null (never run). */
17	  status: string | null;
18	  /** Worst failing tier across evaluated checks, or null (all passed / no run). */
19	  worst_severity: 'warn' | 'fail' | 'critical' | null;
20	  checks_total: number;
21	  checks_passed: number;
22	  finished_at: string | null;
23	  created_at: string | null;
24	}
25	
26	/** One suite composing an asset (caller-visible) — mirrors `ComposingSuiteRead`. */
27	export interface ComposingSuite {
28	  suite_id: string;
29	  name: string;
30	  my_permission: 'owner' | 'admin' | 'edit' | 'view';
31	  latest_run: RunOutcome;
32	}
33	
34	/** List-row aggregation for one visible asset — mirrors `AssetSummaryRead`. */
35	export interface AssetSummary {
36	  id: string;
37	  namespace: string;
38	  name: string;
39	  env: string | null;
40	  description: string | null;
41	  owner_user_id: string | null;
42	  last_seen: string;
43	  suite_count: number;
44	  /** Rolled up across the caller-visible composing suites' latest runs. */
45	  worst_severity: 'warn' | 'fail' | 'critical' | null;
46	  checks_total: number;
47	  checks_passed: number;
48	  last_run_at: string | null;
49	  /** Latest-run execution states (distinct from check severity): any composing
50	   *  suite's latest run `failed` / still `queued`/`running` — an operationally
51	   *  failed run must never render as green health. */
52	  has_failed_run: boolean;
53	  has_active_run: boolean;
54	}
55	
56	/** A lineage neighbour — mirrors `LineageNodeRead`. Render-only (no run data). */
57	export interface LineageNode {
58	  id: string;
59	  namespace: string;
60	  name: string;
61	  env: string | null;
62	  /** Whether the neighbour has ≥1 suite targeting it (a structural fact). */
63	  is_monitored: boolean;
64	}
65	
66	/** Asset detail — mirrors `AssetDetailRead`. */
67	export interface AssetDetail {
68	  summary: AssetSummary;
69	  suites: ComposingSuite[];
70	  upstream: LineageNode[];
71	  downstream: LineageNode[];
72	}
73	
74	/** Metadata mutation payload — mirrors `AssetMetadataUpdate` (admin-only). */
75	export interface AssetMetadataUpdate {
76	  owner_user_id?: string | null;
77	  description?: string | null;
78	}
79	
80	export async function listAssets(params?: {
81	  limit?: number;
82	  offset?: number;
83	}): Promise<AssetSummary[]> {
84	  const { data } = await api.get<AssetSummary[]>('/assets', { params });
85	  return data;
86	}
87	
88	export async function getAsset(assetId: string): Promise<AssetDetail> {
89	  const { data } = await api.get<AssetDetail>(`/assets/${assetId}`);
90	  return data;
91	}
92	
93	/** Update an asset's owner/description (workspace-admin only; backend 403s others). */
94	export async function updateAsset(
95	  assetId: string,
96	  payload: AssetMetadataUpdate,
97	): Promise<AssetSummary> {
98	  const { data } = await api.patch<AssetSummary>(`/assets/${assetId}`, payload);
99	  return data;
100	}
